// Prepare scene data for sub-workflow processing
// T2V does NOT need image_url - generates from text prompt only
const scenes = $('Load Pending Scenes').all().map(i => i.json);
const topicId = $('Webhook Trigger').item.json.body.topic_id;

if (!Array.isArray(scenes) || scenes.length === 0) {
  return [{
    json: {
      scenes: [],
      topic_id: topicId,
      total_scenes: 0,
      skip_processing: true
    }
  }];
}

return [{
  json: {
    scenes: scenes,
    topic_id: scenes[0].topic_id,
    project_id: scenes[0].project_id,
    total_scenes: scenes.length,
    skip_processing: false
  }
}];

// Fire sub-workflow for each scene — adaptive batching
// Small runs (<=10): batch=2, 30s delay. Large runs (>10): batch=1, 60s delay.
// Avoids Fal.ai 429 rate limits while being fast for retries
const { execFileSync, execSync } = require('child_process');

const data = $input.first().json;
const scenes = data.scenes || [];
const topicId = data.topic_id;
const projectId = data.project_id;
const webhookUrl = 'http://localhost:5678/webhook/process-scene/t2v';
const token = $env.DASHBOARD_API_TOKEN;

// Adaptive batching
const BATCH_SIZE = scenes.length <= 10 ? 2 : 1;
const BATCH_DELAY_SEC = scenes.length <= 10 ? 30 : 60;
let fired = 0;

for (let i = 0; i < scenes.length; i += BATCH_SIZE) {
  const batch = scenes.slice(i, i + BATCH_SIZE);

  for (const scene of batch) {
    try {
      execFileSync('curl', [
        '-s', '-o', '/dev/null',
        '-X', 'POST', webhookUrl,
        '-H', 'Content-Type: application/json',
        '-H', 'Authorization: Bearer ' + token,
        '-d', JSON.stringify({
          scene_id: scene.id,
          image_prompt: scene.image_prompt,
          topic_id: topicId,
          project_id: projectId
        }),
        '--connect-timeout', '3',
        '--max-time', '5'
      ]);
      fired++;
    } catch (e) { /* fire-and-forget */ }
  }

  if (i + BATCH_SIZE < scenes.length) {
    execSync('sleep ' + BATCH_DELAY_SEC);
  }
}

return [{ json: { topic_id: topicId, project_id: projectId, fired, total: scenes.length, batch_size: BATCH_SIZE, delay_sec: BATCH_DELAY_SEC } }];

// Check how many T2V scenes are still pending
const { execFileSync } = require('child_process');

const topicId = $input.first().json.topic_id;
const projectId = $input.first().json.project_id;
const url = $env.SUPABASE_URL + '/rest/v1/scenes?topic_id=eq.' + topicId + '&visual_type=eq.t2v&video_status=eq.pending&select=id';

const result = execFileSync('curl', [
  '-s', url,
  '-H', 'apikey: ' + $env.SUPABASE_ANON_KEY,
  '-H', 'Authorization: Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY
]).toString();

const pending = JSON.parse(result);
const count = Array.isArray(pending) ? pending.length : 0;

return [{ json: { pending_count: count, topic_id: topicId, project_id: projectId } }];

// Gather final T2V generation stats from Supabase
const { execFileSync } = require('child_process');

const topicId = $input.first().json.topic_id;
const projectId = $input.first().json.project_id;
const hdr = ['-H', 'apikey: ' + $env.SUPABASE_ANON_KEY, '-H', 'Authorization: Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY];

const uploaded = JSON.parse(execFileSync('curl', ['-s', $env.SUPABASE_URL + '/rest/v1/scenes?topic_id=eq.' + topicId + '&visual_type=eq.t2v&video_status=eq.uploaded&select=id', ...hdr]).toString());
const failed = JSON.parse(execFileSync('curl', ['-s', $env.SUPABASE_URL + '/rest/v1/scenes?topic_id=eq.' + topicId + '&visual_type=eq.t2v&video_status=eq.failed&select=id', ...hdr]).toString());

const completed = Array.isArray(uploaded) ? uploaded.length : 0;
const failedCount = Array.isArray(failed) ? failed.length : 0;
const totalCost = completed * 0.25;

execFileSync('curl', ['-s', '-X', 'PATCH', $env.SUPABASE_URL + '/rest/v1/topics?id=eq.' + topicId, ...hdr, '-H', 'Content-Type: application/json', '-H', 'Prefer: return=minimal', '-d', JSON.stringify({ t2v_progress: 'complete' })]).toString();

return [{ json: { topic_id: topicId, project_id: projectId, completed, failed: failedCount, total_cost: totalCost, stopped: false } }];

// Parallel completion sync: check if ALL visual scenes are done
// FIXED: Correct completion logic per visual_type
// FIXED: Get topic_id from Webhook Trigger as fallback (HTTP Request nodes lose data)
const { execFileSync } = require('child_process');

const data = $input.first().json;
const topicId = data.topic_id || $('Webhook Trigger').item.json.body.topic_id;
const projectId = data.project_id || $('Webhook Trigger').item.json.body.project_id;
const hdr = ['-H', 'apikey: ' + $env.SUPABASE_ANON_KEY, '-H', 'Authorization: Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY];

const supaGet = (path) => JSON.parse(execFileSync('curl', ['-s', $env.SUPABASE_URL + '/rest/v1/' + path, ...hdr]).toString());

if (data.stopped) {
  return [{ json: { ...data, topic_id: topicId, project_id: projectId, assembly_claimed: false, reason: 'stopped' } }];
}

// Count completed scenes correctly:
// static_image: done when image_status=uploaded
// i2v/t2v: done when video_status=uploaded
// any: done when skipped=true
const staticDone = supaGet('scenes?topic_id=eq.' + topicId + '&visual_type=eq.static_image&image_status=eq.uploaded&select=id');
const videoDone = supaGet('scenes?topic_id=eq.' + topicId + '&visual_type=in.(i2v,t2v)&video_status=eq.uploaded&select=id');
const skipped = supaGet('scenes?topic_id=eq.' + topicId + '&skipped=eq.true&select=id');
const completedCount = (Array.isArray(staticDone) ? staticDone.length : 0) + (Array.isArray(videoDone) ? videoDone.length : 0) + (Array.isArray(skipped) ? skipped.length : 0);

const totalScenes = supaGet('scenes?topic_id=eq.' + topicId + '&visual_type=in.(static_image,i2v,t2v)&select=id');
const totalCount = Array.isArray(totalScenes) ? totalScenes.length : 0;

let assemblyClaimed = false;
if (completedCount >= totalCount && totalCount > 0) {
  const r = execFileSync('curl', ['-s', '-X', 'PATCH', $env.SUPABASE_URL + '/rest/v1/topics?id=eq.' + topicId + '&assembly_status=eq.pending', ...hdr, '-H', 'Content-Type: application/json', '-H', 'Prefer: return=representation', '-d', JSON.stringify({ assembly_status: 'starting' })]).toString();
  const claimResult = JSON.parse(r);
  assemblyClaimed = Array.isArray(claimResult) && claimResult.length > 0;
}

return [{ json: { ...data, topic_id: topicId, project_id: projectId, completed_visual_scenes: completedCount, total_visual_scenes: totalCount, assembly_claimed: assemblyClaimed } }];

